'use client'

import { useEffect, useState } from 'react'
import Image from 'next/image'
import Link from 'next/link'

import { FullLogo } from '@/components/icons/logo'
import { OrbitingCircles } from '@/components/magicui/orbiting-circles'

export function OrbitingCirclesDemo() {
  const [radius, setRadius] = useState(236)
  const [innerRadius, setInnerRadius] = useState(170)

  useEffect(() => {
    const updateRadius = () => {
      if (window.innerWidth < 640) {
        // Mobile screens (sm)
        setRadius(180)
        setInnerRadius(120)
      } else if (window.innerWidth < 1024) {
        // Tablets (md)
        setRadius(240)
        setInnerRadius(150)
      } else {
        // Desktops (lg)
        setRadius(236)
        setInnerRadius(170)
      }
    }

    updateRadius() // Set initial radius
    window.addEventListener('resize', updateRadius)

    return () => window.removeEventListener('resize', updateRadius)
  }, [])

  return (
    <div className='mb-10 lg:mb-32'>
      <div className='mx-auto max-w-7xl px-4 md:px-6 lg:px-8'>
        <div className='grid grid-cols-1 gap-8 lg:grid-cols-2 lg:items-center'>
          {/* Left side - Text content */}
          <div className='text-left'>
            <h2 className='text-[40px]/[52px] font-bold text-[#1E1E1E] lg:text-[40px]/[52px]'>
              <span className='text-gradient'>Integrate</span> with the Tools
              you Trust
            </h2>
            <p className='mb-0 mt-4 text-base font-normal text-[#9CA3AF] lg:mb-8 lg:text-lg'>
              Look at the best Partner Onboarding Platform that helps you grow
              your Channel Partners
            </p>
            <div>
              <Link
                href='/integration'
                className='mt-4 rounded-[10px] bg-[#2563EB] px-4 py-2.5 font-semibold text-white'
              >
                Explore integrations
              </Link>
            </div>
          </div>

          {/* Right side - Orbiting circles */}
          <div className='relative mx-auto flex h-[400px] w-[85%] flex-col items-center justify-center overflow-hidden md:h-[550px] md:w-full'>
            <OrbitingCircles
              className='border-[#7688A8]'
              radius={radius}
              iconSize={40}
            >
              <Icons.meet />
              <Icons.hubspot />
              <Icons.video />
              <Icons.sheets />
            </OrbitingCircles>
            <OrbitingCircles
              iconSize={40}
              radius={innerRadius}
              reverse
              speed={2}
            >
              <Icons.slack />
              <Icons.mailchimp />
              <Icons.razorpay />
            </OrbitingCircles>
            <FullLogo className='flex w-[180px] flex-col items-center justify-center' />
          </div>
        </div>
      </div>
    </div>
  )
}

